var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"엇-차!","JPN":"そりゃっ！","ENG":"Oopsie!","TWN":"喝啊！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"해, 해치웠나?","JPN":"た、倒したんですか？","ENG":"D-did we get them?","TWN":"解、解決了嗎？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"쉿, 그런 말 하면 큰일나요.","JPN":"しっ、そんなこと言っちゃダメですよ。","ENG":"Shh, don't say that; you're going to jinx it.","TWN":"噓，說那種話會很不妙喔。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그보다 사람을 공격하지 않고 납치하는 침식체는 저도 처음 보네요.","JPN":"それより、人を襲わずに拉致する侵食体なんて初めて見ます。","ENG":"By the way, I've never seen C.O.s that abduct people instead of attacking them before.","TWN":"不過我還是第一次見到不攻擊人類，而是綁架人類的侵蝕體。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"침식체가 당신에게 첫눈에 반하기라도 한 걸까요?","JPN":"侵食体が一目惚れでもしたんでしょうか？","ENG":"Did they fall in love with you at first sight?","TWN":"該不會是侵蝕體對妳一見鍾情了吧？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아무렇지 않게 무서운 소리 하지 마세요!!","JPN":"しれっと怖いことを言わないでください！？","ENG":"How can you say something so terrible?","TWN":"不要若無其事地說這麼嚇人的話！！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"남자 좀 찾아달랬더니 여자를 데려오질 않나, 침식체를 데려오질 않나!","JPN":"運命の相手を見つけてほしいと言ってたのに、女の人やら侵食体やらを連れてくるなんて！","ENG":"I asked for the man of my dreams, and they brought me a woman and C.O.s instead!","TWN":"我委託你們找的是男人，而不是女人或是侵蝕體！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"당연히 해낼 수 있을 것처럼 자신 있게 말해놓고, 일 처리가 뭐 이따위야?!!","JPN":"自信満々に呼び出すとか言ってたくせに、仕事ぶりがめちゃくちゃじゃない！","ENG":"They acted as if they could find him. How could they do this to me?","TWN":"當初說得信誓旦旦的，結果呢，這算什麼？！！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아, 당신이 운명의 상대를 찾는다던 그 의뢰인?","JPN":"あ、君が運命の相手を探してる依頼人？","ENG":"Ah, so you're their client looking for a soul mate.","TWN":"啊，妳就是那位尋找命運之人的委託人？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"후후, 저로선 남자든 여자든 딱히 상관없긴 한데요.","JPN":"ふふ、私的には男でも女でもどっちでもいいんですけど。","ENG":"Hah hah. I don't care if you're a man or woman.","TWN":"呵呵，我倒是不會特別在意是男還是女。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이쪽에서 단호하게 사양하겠습니다!","JPN":"私からきっぱりとお断りします！","ENG":"I do!","TWN":"容我嚴正拒絕！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"개인의 취향에 대해서는 존중하겠지만 어쨌든 전 남자를 찾고 있어서요.","JPN":"人の好みは尊重しますが、とにかく私は男の人を探しています。","ENG":"I respect your sexual orientation, but I'm personally looking for a man.","TWN":"我尊重妳的個人喜好，但我要男的。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"거 참 변덕스러운 고객이로구나.","JPN":"おやおや、気まぐれな客じゃな。","ENG":"You're such a capricious customer.","TWN":"真是個善變的顧客。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"하지만 걱정 말거라. 내 권능이 실패 따윌 할 리가 없지 않느냐?","JPN":"だが、心配することはない。妾の権能が失敗するわけがないのじゃ。","ENG":"But worry not. There's no way my power fails me.","TWN":"但別擔心，我的力量怎麼可能會失敗呢？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"무슨 소리죠? 이게 실수가 아니었다고요?","JPN":"どういうことですか？　これが失敗じゃなかったと？","ENG":"What are you talking about? Are you telling me this wasn't a mistake?","TWN":"什麼意思？這還不算失敗嗎？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"소환된 것이 네 운명의 상대가 아니라고 해도, 결국 인과의 고리는 서로를 잡아당기기 마련이지.","JPN":"召喚されたのが其方の運命の相手じゃなかったとしても、結局因果の輪は互いを引き寄せるものじゃ。","ENG":"What I summoned may not be your soul mate, but the ones within the same ring of causality are bound to pull each other.","TWN":"即使召喚出來的不是妳命運之人，但因果之環終究會讓兩人相見的。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};